import SwiftUI
struct MetricCard:View{let title,value,detail,icon:String;let tint:Color;var body:some View{VStack(alignment:.leading,spacing:8){Label(title,systemImage:icon).font(.caption.bold()).foregroundStyle(.secondary);Text(value).font(.title2.monospacedDigit().bold()).foregroundStyle(tint);Text(detail).font(.caption).foregroundStyle(.secondary).lineLimit(1)}.frame(maxWidth:.infinity,alignment:.leading).padding().background(.thinMaterial,in:RoundedRectangle(cornerRadius:18))}}
enum Units{static func percent(_ v:Double?)->String{v.map{String(format:"%.0f%%",$0)} ?? "—"};static func bytes(_ v:Double)->String{ByteCountFormatter.string(fromByteCount:Int64(v),countStyle:.memory)};static func rate(_ v:Double?)->String{v.map{ByteCountFormatter.string(fromByteCount:Int64($0),countStyle:.decimal)+"/s"} ?? "—"};static func duration(_ seconds:Double)->String{let d=Int(seconds)/86400,h=(Int(seconds)%86400)/3600;return d>0 ? "\(d)d \(h)h":"\(h)h \((Int(seconds)%3600)/60)m"}}

